  // Itera sobre as 6 imagens obrigatórias
  for (let i = 1; i <= 6; i++) {
    const imagemUrl = item.json[`imagem${i}`] || '';
    const imagemStatus = item.json[`stat_imagem${i}`] || 'rejeitada';

    // Sempre adiciona, mesmo se vazia
    imagens.push({
      url: imagemUrl,
      status: imagemStatus
    });
  }

  // Retorna sempre com 6 imagens
  return {
    json: {
      imagens: imagens
    }
  };
});

// Processa cada item do array de entrada
