// ============================================================
// CALCULA CRITÉRIO DE RELEVÂNCIA DINÂMICO (BASEADO EM DELTA)
//
// Objetivo: Para cada plataforma ativa, encontrar o último
// dia que já tem post agendado e calcular quantos dias faltam
// entre hoje e esse dia (delta). O MAIOR delta entre todas as
// plataformas define o critério mínimo de nota para aprovar
// uma notícia.
//
// Lógica: se qualquer plataforma estiver com a agenda cheia
// lá na frente, o critério sobe para evitar acúmulo em todas.
//
// Se uma plataforma não tiver nenhum post agendado a partir
// de hoje, seu delta é 0 — agenda vazia, critério baixo.
//
// Lógica central (maior delta entre as plataformas):
//   0 dias  → critério 5
//   1 dia   → critério 6
//   2-3     → critério 7
//   4-5     → critério 8
//   6-7     → critério 9
//   8+      → critério 10
// ============================================================

// --- Funções auxiliares ---

// Converte string "DD/MM/YYYY HH:mm" em objeto Date (apenas a data, usando UTC)
// Usa Date.UTC para evitar problemas de timezone — só a data importa para o critério
// Retorna null se inválido ou ausente
function parseDataHora(str) {
  if (!str || str === "-") return null;
  const parts = str.trim().split(" ");
  if (parts.length < 1) return null;
  const datePart = parts[0]; // ignora a hora — para o critério só a data importa
  const [d, m, y] = datePart.split("/");
  if (!d || !m || !y) return null;
  const ms = Date.UTC(+y, +m - 1, +d, 0, 0, 0, 0);
  return isNaN(ms) ? null : new Date(ms);
}

// Converte Date em string "DD/MM/YYYY"
// Usa getUTC* porque as datas são criadas com Date.UTC
function data4(dt) {
  const dd = String(dt.getUTCDate()).padStart(2, "0");
  const MM = String(dt.getUTCMonth() + 1).padStart(2, "0");
  const yyyy = dt.getUTCFullYear();
  return `${dd}/${MM}/${yyyy}`;
}

// Retorna a data de hoje no fuso de São Paulo (UTC-3) como string "DD/MM/YYYY"
// O n8n roda em UTC — precisamos converter para o fuso correto antes de comparar datas
function hojeStrSaoPaulo() {
  // Offset de São Paulo: UTC-3 (sem horário de verão desde 2019)
  const OFFSET_SP_MS = -3 * 60 * 60 * 1000;
  const agoraSP = new Date(Date.now() + OFFSET_SP_MS);
  const dd = String(agoraSP.getUTCDate()).padStart(2, "0");
  const MM = String(agoraSP.getUTCMonth() + 1).padStart(2, "0");
  const yyyy = agoraSP.getUTCFullYear();
  return `${dd}/${MM}/${yyyy}`;
}

// Converte string "DD/MM/YYYY" em número inteiro YYYYMMDD para comparação simples
// Ex: "03/03/2026" → 20260303
function dataParaNum(str) {
  const [d, m, y] = str.split("/");
  return +y * 10000 + +m * 100 + +d;
}

// Calcula delta em dias entre hoje (SP) e uma data futura (string "DD/MM/YYYY")
// Usa Date.UTC para aritmética pura de dias sem influência de DST ou timezone
// Retorna 0 se a data for hoje ou no passado
function deltaDias(dataFuturaStr) {
  const hojeStr = hojeStrSaoPaulo();
  if (dataParaNum(dataFuturaStr) <= dataParaNum(hojeStr)) return 0;
  const [dH, mH, yH] = hojeStr.split("/");
  const [dF, mF, yF] = dataFuturaStr.split("/");
  const msHoje = Date.UTC(+yH, +mH - 1, +dH);
  const msFut  = Date.UTC(+yF, +mF - 1, +dF);
  return Math.round((msFut - msHoje) / (1000 * 60 * 60 * 24));
}

// Mapeia o maior delta → critério de relevância
function deltaToCriterio(delta) {
  if (delta <= 0) return 5;
  if (delta <= 1) return 6;
  if (delta <= 3) return 7;
  if (delta <= 5) return 8;
  if (delta <= 7) return 9;
  return 10; // 8+ dias
}

// -------------------------------------------------------

// --- Dados do cliente ---
const configCliente = $('Pega dados fixos do cliente').first().json;

// --- Detecta plataformas ativas dinamicamente ---
// Lê todas as chaves "config_postagem_*" e filtra as com "ativo: true"
const plataformasAtivas = [];
const configsPorPlataforma = {};

for (const chave of Object.keys(configCliente)) {
  if (!chave.startsWith("config_postagem_")) continue;

  try {
    const nomePlat = chave.replace("config_postagem_", "");
    const cfg = JSON.parse(configCliente[chave]);

    if (!cfg.ativo) continue;

    plataformasAtivas.push(nomePlat);
    configsPorPlataforma[nomePlat] = cfg;
  } catch (e) {
    // JSON mal formatado, ignora silenciosamente
  }
}

// --- Carrega posts agendados filtrados por fonte ---
// Apenas IDEIAS e RSS consomem slots de agendamento.
// RESUMO SEMANAL e outras fontes não são contabilizadas.
const fontesFiltradas = ["IDEIAS", "RSS"];
const todosOsPosts = $('Info dos posts agendados').all().map(i => i.json);
const postsFiltrados = todosOsPosts.filter(post =>
  fontesFiltradas.includes((post.fonte || "").trim().toUpperCase())
);

// Hoje em São Paulo como string "DD/MM/YYYY" e como número para comparação
const hojeStr = hojeStrSaoPaulo();
const hojeNum = dataParaNum(hojeStr);

// --- Para cada plataforma ativa, encontra o último dia agendado ---
// Varre todos os posts filtrados, pega os horários de cada plataforma
// e identifica a data mais distante a partir de hoje (inclusive).
//
// Delta = dias entre hoje e esse último dia agendado.
// Se não houver nenhum post agendado a partir de hoje → delta = 0.

const deltas = [];
const detalhePorPlataforma = {};

for (const plat of plataformasAtivas) {
  const cfg = configsPorPlataforma[plat];
  let ultimaDataStr = null; // string "DD/MM/YYYY" do post mais distante nessa plataforma
  let ultimaDataNum = 0;    // número YYYYMMDD para comparação rápida

  for (const post of postsFiltrados) {
    const horario = parseDataHora(post[`horario_post_${plat}`]);
    if (!horario) continue;

    // Converte para string no mesmo formato para comparação consistente
    const dataStr = data4(horario);
    const dataNum = dataParaNum(dataStr);

    // Ignora posts no passado — só conta a partir de hoje inclusive
    if (dataNum < hojeNum) continue;

    // Guarda a data mais distante encontrada
    if (dataNum > ultimaDataNum) {
      ultimaDataStr = dataStr;
      ultimaDataNum = dataNum;
    }
  }

  const delta = ultimaDataStr ? deltaDias(ultimaDataStr) : 0;
  deltas.push(delta);

  detalhePorPlataforma[plat] = {
    ultimo_dia_agendado: ultimaDataStr || "-", // ex: 07/03/2026
    delta_dias: delta,                          // ex: 5
    posts_por_dia: cfg.posts_por_dia,
    dias_ativos: cfg.dias_semana
  };
}

// --- Pega o maior delta entre todas as plataformas ativas ---
// Se qualquer plataforma estiver com agenda cheia lá na frente,
// o critério sobe para proteger todas as plataformas de acúmulo.
const maiorDelta = deltas.length > 0 ? Math.max(...deltas) : 0;

// --- Define o critério dinâmico com base no maior delta ---
const criterioDinamico = deltaToCriterio(maiorDelta);

// --- Retorna o resultado para uso no nó IF ---
return [{
  json: {
    criterio_relevancia_dinamico: criterioDinamico,   // valor usado no nó IF
    maior_delta_dias: maiorDelta,                     // ex: 5 — plataforma mais cheia
    hoje: hojeStr,                                    // ex: 02/03/2026 — confirma fuso SP
    plataformas_ativas: plataformasAtivas,            // ex: ["instagram", "x", ...]
    detalhe_por_plataforma: detalhePorPlataforma      // breakdown completo por plataforma
  }
}];

return $input.all()
  .sort((a, b) => b.json.nota - a.json.nota)
  .map(item => ({ json: item.json }));

// ======================================
// AGENDADOR INTELIGENTE
// ======================================
// Busca o próximo slot livre para cada plataforma aprovada,
// sem limite de semana — olha para frente livremente até
// encontrar o próximo horário disponível.
//
// Usa fuso de São Paulo (UTC-3) para garantir que o dia de
// início da busca seja sempre o correto, independente do
// horário UTC do servidor do n8n.
// ======================================

const mapa = $input.first().json.mapa_ocupados || {};
const fixo = $items("Pega dados fixos do cliente")[0].json;

// Resultado do aprovador
const aprovador = $items("Call 'Tools - 9 - Aprovador'")[0].json;

function parseCfg(str) {
  try { return JSON.parse(str); } catch { return null; }
}

// Retorna a data de hoje no fuso de São Paulo (UTC-3) como objeto Date (meia-noite UTC)
// Evita que o servidor em UTC interprete o dia errado nas madrugadas de SP
function hojeBaseSP() {
  const OFFSET_SP_MS = -3 * 60 * 60 * 1000;
  const agoraSP = new Date(Date.now() + OFFSET_SP_MS);
  return new Date(Date.UTC(
    agoraSP.getUTCFullYear(),
    agoraSP.getUTCMonth(),
    agoraSP.getUTCDate(),
    0, 0, 0, 0
  ));
}

// Converte Date (criado com Date.UTC) em string "DD/MM/YYYY"
// Usa getUTC* para ser consistente com hojeBaseSP
function data4(dt) {
  const dd = String(dt.getUTCDate()).padStart(2, "0");
  const MM = String(dt.getUTCMonth() + 1).padStart(2, "0");
  const yyyy = dt.getUTCFullYear();
  return `${dd}/${MM}/${yyyy}`;
}

// Formata data + hora para string "DD/MM/YYYY HH:mm"
// Usa getUTC* para ser consistente com as datas criadas em UTC
function formatar(dt, hora) {
  const d = new Date(dt);
  const [hh, mm] = hora.split(":");
  const comHora = new Date(Date.UTC(
    d.getUTCFullYear(),
    d.getUTCMonth(),
    d.getUTCDate(),
    +hh, +mm, 0, 0
  ));

  const dd = String(comHora.getUTCDate()).padStart(2, "0");
  const MM = String(comHora.getUTCMonth() + 1).padStart(2, "0");
  const yy = comHora.getUTCFullYear();
  const HH = String(comHora.getUTCHours()).padStart(2, "0");
  const mm2 = String(comHora.getUTCMinutes()).padStart(2, "0");

  return `${dd}/${MM}/${yy} ${HH}:${mm2}`;
}

// Avança a data em 1 dia usando milissegundos
function proximoDia(dt) {
  return new Date(dt.getTime() + 24 * 60 * 60 * 1000);
}

const dias = ["dom", "seg", "ter", "qua", "qui", "sex", "sab"];

const plataformas = Object.keys(fixo)
  .filter(k => k.startsWith("config_postagem_"))
  .map(k => k.replace("config_postagem_", ""));

// Inicializa retorno com "-" para todas as plataformas
const retorno = {};
for (const p of plataformas) {
  retorno[`horario_post_${p}`] = "-";
}

for (const p of plataformas) {

  // Só agenda plataformas aprovadas pelo aprovador
  const statusPlataforma = aprovador?.[p]?.status;
  if (statusPlataforma !== "aprovado") continue;

  const cfg = parseCfg(fixo[`config_postagem_${p}`]);
  if (!cfg || !cfg.ativo) continue;
  if (!Array.isArray(cfg.horarios)) continue;
  if (!Array.isArray(cfg.dias_semana)) continue;
  if (!cfg.posts_por_dia || cfg.posts_por_dia < 1) continue;

  let d = hojeBaseSP();
  let agendado = false;

  // Busca para frente sem limite de semana — até 90 dias
  for (let tentativa = 0; tentativa < 90 && !agendado; tentativa++) {
    const dia = dias[d.getUTCDay()]; // getUTCDay() consistente com datas criadas em UTC
    const dataStr = data4(d);

    if (cfg.dias_semana.includes(dia)) {
      const ocupados = mapa[p]?.[dataStr] || [];

      if (ocupados.length < cfg.posts_por_dia) {
        for (const hora of cfg.horarios) {
          if (!ocupados.includes(hora)) {
            retorno[`horario_post_${p}`] = formatar(d, hora);
            agendado = true;
            break;
          }
        }
      }
    }

    if (!agendado) {
      d = proximoDia(d);
    }
  }
}

return [{ json: retorno }];

// ========================
// MAPA GLOBAL DE HORÁRIOS OCUPADOS
// (a partir de hoje em diante)
// ========================
// Lê todos os posts agendados e monta um mapa por plataforma
// e data, contendo os horários já ocupados.
//
// Usado pelo Agendador para saber quais slots já estão tomados
// e encontrar o próximo horário livre para cada plataforma.
//
// Considera apenas posts a partir de hoje (SP) — ignora passado.
// ========================

const historico = $items("Info dos posts agendados").map(i => i.json);
const mapa = {};

// -------------------------

// Valida se a string é uma data no formato DD/MM/YYYY
function isDataValida(d) {
  return /^\d{2}\/\d{2}\/\d{4}$/.test(d);
}

// Valida se a string é uma hora no formato HH:mm
function isHoraValida(h) {
  return /^\d{2}:\d{2}$/.test(h);
}

// Converte string "DD/MM/YYYY" em número YYYYMMDD para comparação simples
// Evita qualquer problema de timezone — compara apenas o valor numérico da data
function dataParaNum(str) {
  const [d, m, y] = str.split("/");
  return +y * 10000 + +m * 100 + +d;
}

// Retorna a data de hoje no fuso de São Paulo (UTC-3) como string "DD/MM/YYYY"
// O n8n roda em UTC — precisamos converter para o fuso correto
function hojeStrSP() {
  const OFFSET_SP_MS = -3 * 60 * 60 * 1000;
  const agoraSP = new Date(Date.now() + OFFSET_SP_MS);
  const dd = String(agoraSP.getUTCDate()).padStart(2, "0");
  const MM = String(agoraSP.getUTCMonth() + 1).padStart(2, "0");
  const yyyy = agoraSP.getUTCFullYear();
  return `${dd}/${MM}/${yyyy}`;
}

