// pega config dinâmica (do nó de dados do cliente)
const configNode = $('Pega dados fixos do cliente').first();
let regrasFonte = [];

try {
  let raw = configNode.json.prioridade_fonte;

  if (raw) {
    // força aspas no campo link se não tiver
    raw = raw.replace(/"link":\s*([^",}\n]+)/g, '"link":"$1"');

    // transforma em array
    const parsed = JSON.parse(`[${raw}]`);

    regrasFonte = parsed;
  }
} catch (e) {
  console.log('Erro ao parsear prioridade_fonte:', e);
  regrasFonte = [];
}

return noticias.map(item => {
  const link = item.json.link || '';

