      contentSnippet: item.json.contentSnippet,
      isoDate: item.json.isoDate,
      total_ideias_anteriores: ideiasAnteriores.length,
      ideias_completas: ideiasAnteriores,

      // dinâmico agora
      regra_fonte: regraFonte,
      prioridade_fonte: prioridade
    }
  };
});
